modules.fpm_unpack:
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);

    // Unpack a
    wire a_sign_bit = a[31];
    wire [7:0] a_exp_bits = a[30:23];
    wire [22:0] a_mant_bits = a[22:0];

    // Unpack b
    wire b_sign_bit = b[31];
    wire [7:0] b_exp_bits = b[30:23];
    wire [22:0] b_mant_bits = b[22:0];

    // Detect special cases for a
    wire a_is_zero_int = (a_exp_bits == 8'b0) && (a_mant_bits == 23'b0);
    wire a_is_denormal = (a_exp_bits == 8'b0) && (a_mant_bits != 23'b0);
    wire a_is_inf_int = (a_exp_bits == 8'hFF) && (a_mant_bits == 23'b0);
    wire a_is_nan_int = (a_exp_bits == 8'hFF) && (a_mant_bits != 23'b0);

    // Detect special cases for b
    wire b_is_zero_int = (b_exp_bits == 8'b0) && (b_mant_bits == 23'b0);
    wire b_is_denormal = (b_exp_bits == 8'b0) && (b_mant_bits != 23'b0);
    wire b_is_inf_int = (b_exp_bits == 8'hFF) && (b_mant_bits == 23'b0);
    wire b_is_nan_int = (b_exp_bits == 8'hFF) && (b_mant_bits != 23'b0);

    // Mantissa with implicit leading 1 for normalized numbers, or as-is for denormals
    wire [23:0] a_mant_normalized = a_is_denormal ? {1'b0, a_mant_bits} : {1'b1, a_mant_bits};
    wire [23:0] b_mant_normalized = b_is_denormal ? {1'b0, b_mant_bits} : {1'b1, b_mant_bits};

    // Assign outputs for a
    assign a_sign = a_sign_bit;
    assign a_exp = a_exp_bits;
    assign a_mant = a_mant_normalized;
    assign a_is_nan = a_is_nan_int;
    assign a_is_inf = a_is_inf_int;
    assign a_is_zero = a_is_zero_int;

    // Assign outputs for b
    assign b_sign = b_sign_bit;
    assign b_exp = b_exp_bits;
    assign b_mant = b_mant_normalized;
    assign b_is_nan = b_is_nan_int;
    assign b_is_inf = b_is_inf_int;
    assign b_is_zero = b_is_zero_int;

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    // Result sign is XOR of input signs
    assign result_sign = a_sign ^ b_sign;

    // Product of mantissas (24-bit × 24-bit = 48-bit)
    assign product = a_mant * b_mant;

    // Raw exponent: sum of exponents minus bias
    // In IEEE 754, bias is 127. When multiplying, exp_result = exp_a + exp_b - bias
    assign raw_exp = {1'b0, a_exp} + {1'b0, b_exp} - 10'd127;

endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    wire [22:0] norm_frac_unshifted;
    wire [22:0] norm_frac_shifted;
    wire guard_unshifted;
    wire guard_shifted;
    wire sticky_unshifted;
    wire sticky_shifted;

    // When bit 47 is clear: extract bits [45:23] as fraction, bit 22 as guard, OR of [21:0] as sticky
    assign norm_frac_unshifted = product[45:23];
    assign guard_unshifted = product[22];
    assign sticky_unshifted = |product[21:0];

    // When bit 47 is set: right-shift, extract bits [46:24] as fraction, bit 23 as guard, OR of [22:0] as sticky
    assign norm_frac_shifted = product[46:24];
    assign guard_shifted = product[23];
    assign sticky_shifted = |product[22:0];

    // Select based on bit 47
    assign norm_frac = product[47] ? norm_frac_shifted : norm_frac_unshifted;
    assign guard = product[47] ? guard_shifted : guard_unshifted;
    assign sticky = product[47] ? sticky_shifted : sticky_unshifted;

    // Exponent adjustment
    assign norm_exp = product[47] ? (raw_exp + 10'd1) : raw_exp;

endmodule

modules.fpm_round_pack:
`timescale 1ns/1ps
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);
    always @(*) begin
        overflow = 0;
        underflow = 0;
        result = 0;

        // Check for underflow (exponent is 0)
        if (norm_exp == 10'd0) begin
            underflow = 1;
            result = {sign, 31'b0};  // Return signed zero
        end
        // Check for overflow (exponent is 255 or more)
        else if (norm_exp >= 10'd255) begin
            overflow = 1;
            // Return signed infinity
            result = {sign, 8'b11111111, 23'b0};
        end
        else begin
            // Normal case: pack the number
            reg [22:0] frac_to_pack;
            reg [8:0] exp_to_pack;

            // Determine if we should round up
            reg round_up;
            round_up = 0;

            if (guard == 1) begin
                // Guard bit is 1
                if (sticky == 1) begin
                    // guard=1, sticky=1: always round up
                    round_up = 1;
                end
                else begin
                    // guard=1, sticky=0: round up only if LSB is 1 (banker's rounding)
                    round_up = norm_frac[0];
                end
            end

            // Apply rounding
            if (round_up) begin
                frac_to_pack = norm_frac + 23'd1;
                // Check if fraction overflowed (all 1s became 0s + carry)
                if (frac_to_pack == 23'd0) begin
                    // Fraction overflowed, increment exponent
                    exp_to_pack = norm_exp[8:0] + 9'd1;
                end
                else begin
                    exp_to_pack = norm_exp[8:0];
                end
            end
            else begin
                frac_to_pack = norm_frac;
                exp_to_pack = norm_exp[8:0];
            end

            // Pack into IEEE 754 format
            result = {sign, exp_to_pack, frac_to_pack};
        end
    end
endmodule

modules.fpm_special:
`timescale 1ns/1ps
module fpm_special(
    input         a_is_nan,
    input         a_is_inf,
    input         a_is_zero,
    input         b_is_nan,
    input         b_is_inf,
    input         b_is_zero,
    input         result_sign,
    output        is_special,
    output reg [31:0] special_result
);

    wire is_nan;
    wire is_inf_times_zero;
    wire is_inf;
    wire is_zero;

    // NaN if either input is NaN
    assign is_nan = a_is_nan | b_is_nan;

    // Inf × 0 or 0 × Inf is NaN
    assign is_inf_times_zero = (a_is_inf & b_is_zero) | (a_is_zero & b_is_inf);

    // Result is special if any special case detected
    assign is_special = is_nan | is_inf_times_zero | a_is_inf | b_is_inf | a_is_zero | b_is_zero;

    // Determine if result should be Inf (but not if it's Inf×0 which becomes NaN)
    assign is_inf = (a_is_inf | b_is_inf) & ~is_inf_times_zero;

    // Determine if result should be Zero (but not if it's Inf×0 which becomes NaN)
    assign is_zero = (a_is_zero | b_is_zero) & ~is_inf_times_zero;

    always @(*) begin
        if (is_nan | is_inf_times_zero) begin
            // Output NaN: 0x7FC00000
            special_result = 32'h7FC00000;
        end
        else if (is_inf) begin
            // Output Infinity with sign
            special_result = {result_sign, 8'hFF, 23'h0};
        end
        else if (is_zero) begin
            // Output Zero with sign
            special_result = {result_sign, 31'h0};
        end
        else begin
            special_result = 32'h0;
        end
    end

endmodule
